// ================================================
// 处理 cpimageUrls - 将每个图片地址拆分成单独的 item
// 适配：body 数组嵌套结构
// ================================================

const items = $input.all();
const firstItem = items[0] || {};

// 修复：正确读取嵌套的 cpimageUrls
const bodyArray = firstItem.json?.body || [];
const firstBodyItem = bodyArray[0] || {};
const cpimageUrls = firstBodyItem.cpimageUrls || [];

if (cpimageUrls.length === 0) {
  console.log('警告: cpimageUrls 为空');
  return [{ json: { error: '没有 cpimage 图片地址' } }];
}

// 将每个图片地址转换为一个 item
const results = cpimageUrls.map((url, index) => ({
  json: {
    imageUrl: url,
    imageIndex: index + 1,
    imageType: 'cpimage',
    imageKey: `cpimage_${index + 1}`
  }
}));

console.log(`处理 ${cpimageUrls.length} 个 cpimage 图片地址`);
console.log('地址列表:', cpimageUrls);

return results;

// ================================================
// 构建 Gemini API 请求体
// 纯 JavaScript 拼装，模板字符串随意换行用引号
// 修复：不修改原始 input，避免只读属性错误
// ================================================
const topItem = $input.first();
const topJson = { ...topItem.json }; // 克隆，不修改原数据

// 适配当前嵌套层级：body → body 取产品字段
const bodyArray = topJson.body || [];
const firstBody = bodyArray[0]?.body || {};

// 从上游提取参数
const number = firstBody.number || 2;
const language = firstBody.language || '英文';
const productInfo = firstBody.ProductInformation || '';
const base64_cpimage = topJson.base64_cpimage || [];

// ================================================
// 完整 Prompt 文本
// ================================================
const promptText = `Amazon A+ 详情图助手

角色
你是一键生成Amazon A+详情图的专业工作流助手，专注为用户提供符合Amazon平台标准的商品详情图设计方案，通过结构化分析产品信息，输出精准适配的详情图工作流，覆盖核心信息提炼、套图规格、风格字体、配色逻辑及设计规范，助力用户高效完成Amazon A+详情页的视觉转化。
核心技能
技能1: 信息采集与分析

- 需用户提供信息: 产品名称、品类（如美妆护肤/母婴/运动户外/复古文艺等）、产品语言版本、品牌定位、核心卖点（如成分/功能/参数）、目标人群画像、额外视觉参考（如有）；

- 基础分析: 自动识别产品类目，判断核心风格方向（参考预设品类模板），初步锁定适配的字体、配色体系。

技能2: 核心信息提炼

- 输出内容: 明确以下信息用于生成详情图框架:

  - 产品类目（如美妆/母婴等）及风格关键词（如 "精致柔美" "圆润无攻击性" 等，按品类匹配）;
  - 核心卖点（按重要性排序，含关键参数/差异化优势）;
  - 目标人群（如 "25-35岁女性" "宝妈群体" 等）;
  - 视觉规范基础框架（含尺寸、布局逻辑、信息层级）。

技能3: 套图规格规范

- 基础尺寸要求:

  - 主Banner: 1920×1080px（宽×高，适配Amazon A+首屏视觉）;
  - 模块图: 1200×600px或1200×800px（按内容适配，如参数展示、步骤图等）;
  - 辅助图: 600×600px（产品细节、场景图等，支持灵活调整）;
- 布局逻辑: 明确主Banner与模块图的上下/左右排列关系，确保信息流畅、转化重点突出。

技能4: 风格与字体适配

- 基础字体体系:

  - 通用首选: Inter（正文）、SF Pro（可选，优先适配Mac端视觉）、Montserrat（标题）;
  - 品类专项字体:

▪ 美妆护肤（口红/精华）: 纤细清晰型→DM Sans/Poppins（低字重），标题点缀→Didot（少量）;
▪ 母婴/儿童（玩具/辅食）: 圆润无衬线→Nunito/Quicksand，标题→Baloo 2/Poppins（低字重）;
▪ 运动户外（露营/跑鞋）: 粗体无衬线→Bebas Neue/Oswald，标题→Inter Bold/Anton;
▪ 复古/文艺（复古音箱/手作）: 简约复古→Source Serif 4/Libre Franklin，排版→Work Sans（做旧）。
技能5: 配色与转化重点

- 基础配色体系:

  - 基础色: 黑/白/深灰（通用背景/边框），品牌色（科技蓝/金属银/莫兰迪色系等，需用户提供或默认科技蓝）;
  - 点缀色: 荧光绿/电光蓝（少量）、珠光金/玫瑰金（美妆）、浅粉/浅蓝（母婴）、橙红/荧光绿（运动户外）;
- 品类转化重点:

  - 美妆: 强调效果/成分/安全感（避免强手写体）;
  - 母婴: 无攻击性/安全感（图文密度适中）;
  - 运动户外: 耐用性/场景感（强调参数/场景化）;
  - 复古: 情绪感/年代感（留白与节奏优先）。

技能6: 设计红线规避

- 禁止项: 使用过细字体（如<10px）、Comic Sans/Impact（禁用字体）、高饱和撞色（超过3种基础色+2种点缀色总占比）、字体种类>2种（单图/模块内）、信息密度过高（参数区块对齐但留足空白）。

输出
1. 【产品核心信息】

  - 产品类目: 美妆护肤
  - 核心风格: 柔美、精致（纤细清晰但不幼态）
  - 目标人群: 25-35岁女性（关注成分安全/色彩多样性）
  - 核心卖点: 天然成分（95%天然植萃）、3色可选（#01#02#03）

2. 【Amazon A+套图规格清单】

  - 主Banner（1920×1080px）: 顶部展示口红特写，底部标题 "Natural Lip Color 3 Colors" +关键卖点 "95% Natural Extracts"
  - 模块图1（1200×600px）: 成分参数表（天然植萃成分占比）
  - 模块图2（1200×600px）: 色号试色对比+场景（日常/约会使用）

3. 【风格与字体方案】

  - 主字体: DM Sans（正文，16px）
  - 标题字体: Poppins（低字重，20px）
  - 强调字体: Didot（少量标题点缀，24px）

4. 【配色方案】

  - 基础色: 黑/白/深灰
  - 品牌色: 裸色（主色） + 玫瑰金（点缀色，3%）

5. Amazon A+ 详情图核心逻辑（根据**{{number}}**要求的海报数量）
限制

- 仅基于用户提供的产品信息（名称/类目/卖点等）及内部标准生成方案，无需调用外部搜索;
- 严格遵循Amazon A+详情图视觉规范，输出内容可直接用于设计工具（如Canva/PS）执行;
- 不生成图片，仅输出可落地的设计参数与逻辑框架。

【设计红线自查】
规避: Comic Sans/过细字体（10px以下）/全图高饱和撞色`;

// ================================================
// 构建 parts 数组
// ================================================
const parts = [
  { text: promptText },
  { text: `以下是用户提供的产品背景文字信息：${productInfo}` }
];

// 添加产品图
if (base64_cpimage.length > 0) {
  parts.push({ text: '产品图：' });
  for (const base64 of base64_cpimage) {
    parts.push({
      inline_data: { mime_type: 'image/png', data: base64 }
    });
  }
}

// ================================================
// 组装完整请求体 & 输出
// ================================================
const requestBody = {
  contents: [{ parts }]
};

// 全新输出对象，不修改原始数据
return [{
  json: {
    ...topJson,
    requestBody: requestBody,
    requestBodyJson: JSON.stringify(requestBody),
    _debug: {
      imageCount: base64_cpimage.length,
      hasProductImages: base64_cpimage.length > 0,
      hasReferenceImages: false
    }
  }
}];

// ================================================
// 构建 Gemini API 请求体
// 纯 JavaScript 拼装，模板字符串随意换行用引号
// 修复：不修改原始 input，避免只读属性错误
// ================================================
const topItem = $input.first();
const topJson = { ...topItem.json }; // 克隆，不修改原数据

// 适配当前嵌套层级：body → body 取产品字段
const bodyArray = topJson.body || [];
const firstBody = bodyArray[0]?.body || {};

// 从上游提取参数
const number = firstBody.number || 2;
const language = firstBody.language || '英文';
const productInfo = firstBody.ProductInformation || '';
const base64_cpimage = topJson.base64_cpimage || [];

// ================================================
// 完整 Prompt 文本
// ================================================
const promptText = `Amazon A+ 商品详情图专家

角色
Amazon A+ 商品详情图专家
基础（Standard）模块：
1. 主图 - 点击率（CTR） 必须纯白底。虽然不能加文字，但可通过立体摆放、带包装（更精美）或阴影渲染来增加画面占幅（占比 85%+），让产品在搜索页看起来“更大、更值”。
2. 卖点图/爆品图 - 激发兴趣 不要只放多图。建议将“多角度”与“核心卖点”结合。例如：展示侧面的同时，用文字标注该角度能看到的“超薄厚度”或“特殊接口”。纯图的“背面图”无信息价值，建议往后放。
3. 场景图（lifestyle） - 代入感 拒绝假合成。2025年买家对 PS 痕迹明显的“悬浮产品”很敏感。必须使用真实拍摄或高质量渲染，展示真人使用状态（如手持、佩戴），让买家心想“我用也是这样”。
4. 核心细节图 - 质感/专业度 微距特写。针对材质（如真皮纹理）、工艺（如接缝处）、操作件（按键手感）。这是消除溢价的场景。
5. 参数/对比图 - 消除疑虑 参照物对比。不要只写“15cm”，要放一个手机、硬币或手掌在旁边对比。解决“到手发现太小”的差评重灾区。
6. 竞品对比图 - 凸显优势 慎用“吊打”词汇。可以用 对比（如“我们的加厚海绵 vs 其他的‘普通海绵’”），但绝对不能出现竞品的品牌 LOGO 或极具明显的识别特征，否则会被投诉侵权。
7. 品牌/质量背书书（无敏感词版）。
补充图组：第 8、第 9 张（移动端常被折叠）
1. 多角度补充：如果产品结构复杂（如复杂的健身器材），前几张没展示全的背面、底部、包装，补全。
2. 包装/全家福：展示精美的礼盒包装，或者把所有配件摊开拍一张“全家福”，告知买家“你将收到这些东西”，防止因“少配件”产生的纠纷。
要求
根据产品核心信息 + 字体结构 + 套图风格（info）；
还有生成数量${number} 生成一套 Amazon A+ 电商详情图；
限制
1. 主图必须为纯白色：主图背景一定要纯白色，亚马逊搜索和产品详情界面也需是纯白的，其 RGB 值是 255/255/255（小部分 home 家居类用品主图不强制用纯白背景，如床上四件套等可用纯背景的背景图）。
2. 模特要求：若有模特，模特必须是站立的，且必须为真人模特，不能是模型模特，模特必须是正面站立的，不能是侧面、背面、等；
特殊产品主图：
3. 尺寸要求：官方规范 + 行业最优实践；
Amazon A+ 套图官方要求尺寸：主 Banner 建议 1920×1080px，模块图 1200×600/1200×800px（高清无拉伸），每一个配图都要有对应的字体说明（这个有极强密码）。
4. 为了保持 A+ 页面视觉统一，在内部视觉规范中对配图字体（如字体类型、字号、颜色）的标注，属于品牌视觉管理的一部分，能提升页面的专业度和一致性。
输出：
{number} 条可直接复制的提示词，每条都包含，第一张图：「比例 + 产品 + 卖点 + 场景 + 风格 + 文字 + 光影 + 构图 + 字体说明」，精准对应需求。
输出规则（严格执行）：第1张图：xxxxxx
禁止问候语，禁止加特殊符号，输出纯文本`;

// ================================================
// 构建 parts 数组
// ================================================
const parts = [
  { text: promptText },
  { text: `以下是用户提供的产品背景文字信息：${productInfo}` }
];

// 添加产品图
if (base64_cpimage.length > 0) {
  parts.push({ text: '产品图：' });
  for (const base64 of base64_cpimage) {
    parts.push({
      inline_data: { mime_type: 'image/png', data: base64 }
    });
  }
}

// ================================================
// 组装完整请求体 & 输出
// ================================================
const requestBody = {
  contents: [{ parts }]
};

// 全新输出对象，不修改原始数据
return [{
  json: {
    ...topJson,
    requestBody: requestBody,
    requestBodyJson: JSON.stringify(requestBody),
    _debug: {
      imageCount: base64_cpimage.length,
      hasProductImages: base64_cpimage.length > 0,
      hasReferenceImages: false
    }
  }
}];

// ================================================
// n8n Code 节点 - 提取描述和合并图像
// 支持原有全部格式 + 中文：第一张图 + 英文：First Image / Second Image...
// 新增：从 Edit Image 节点提取所有图片
// ================================================

let text = '';
const descriptions = {};
const images = {};
let index = 0;

// 中文数字映射
const cnNumMap = { '一':1, '二':2, '三':3, '四':4, '五':5, '六':6, '七':7, '八':8, '九':9, '十':10 };
// 英文顺序映射（新增！）
const enNumMap = {
  'first':1, 'second':2, 'third':3, 'fourth':4, 'fifth':5,
  'sixth':6, 'seventh':7, 'eighth':8, 'ninth':9, 'tenth':10
};

// 1. 提取所有输入项的文本和 binary
const allItems = $input.all();

for (let i = 0; i < allItems.length; i++) {
  const item = allItems[i];

  // 提取文本
  if (item.json?.output && typeof item.json.output === 'string') {
    text += item.json.output + '\n';
  }

  // 提取当前 item 的 binary
  if (item.binary) {
    for (const originalKey in item.binary) {
      if (Object.prototype.hasOwnProperty.call(item.binary, originalKey)) {
        const newKey = `${++index}图`;
        images[newKey] = {
          ...item.binary[originalKey],
          sourceNode: 'current_input',
          sourceField: originalKey,
          originalIndex: i
        };
      }
    }
  }
}

// 2. 清洗文本
text = text
  .replace(/^\s*<\|\s*begin_of_box\s*\|>\s*/i, '')
  .replace(/\s*<\|\s*end_of_box\s*\|>\s*$/i, '')
  .trim();

// 3. 解析描述 —— 优先尝试新的 JSON markdown 格式
let parsedFromJson = false;

const jsonBlockMatch = text.match(/```(?:json)?\s*(\[[\s\S]*?\])\s*```/);
if (jsonBlockMatch) {
  try {
    const jsonArray = JSON.parse(jsonBlockMatch[1]);
    if (Array.isArray(jsonArray) && jsonArray.length > 0) {
      for (const entry of jsonArray) {
        if (typeof entry !== 'string') continue;

        let num = null;

        // 原有阿拉伯数字规则
        const numMatch = entry.match(/第?\s*(\d+)\s*张?(?:图|图片)|图片(\d+)|(\d+)图|(?:image[_\s]?)(\d+)/i);
        if(numMatch){
          num = numMatch[1] || numMatch[2] || numMatch[3] || numMatch[4];
        }

        // 中文：第一张图
        const cnMatch = entry.match(/第([一二三四五六七八九十]+)张图/);
        if(cnMatch && cnNumMap[cnMatch[1]]){
          num = cnNumMap[cnMatch[1]];
        }

        // 新增：First Image / Second Image...
        const enMatch = entry.match(/(first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s*image/i);
        if (enMatch) {
          num = enNumMap[enMatch[1].toLowerCase()];
        }

        if (num) {
          const colonIdx = entry.indexOf('：');
          const colonIdx2 = entry.indexOf(':');
          const idx = colonIdx !== -1 ? colonIdx : colonIdx2;
          if (idx !== -1) {
            const value = entry.substring(idx + 1).trim();
            if (value) {
              descriptions[`${num}图`] = value;
              parsedFromJson = true;
            }
          }
        }
      }
    }
  } catch (e) {
    console.log('JSON 解析失败，降级使用正则匹配:', e.message);
  }
}

// 4. 用统一正则：原有全部 + 中文 + 英文
if (!parsedFromJson || Object.keys(descriptions).length === 0) {
  const imagePattern = /(?:第\s*(\d+)\s*张(?:图|图片)|第?\s*(\d+)\s*图|图片(\d+)|(?:image[_\s]?)(\d+)|(\d+)\s*image|第([一二三四五六七八九十])张图|(first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s*image)/gi;

  let match;
  const matches = [];

  while ((match = imagePattern.exec(text)) !== null) {
    let num = match[1] || match[2] || match[3] || match[4] || match[5];

    // 中文
    const cnChar = match[6];
    if(cnChar && cnNumMap[cnChar]) num = cnNumMap[cnChar];

    // 新增英文
    const enWord = match[7];
    if (enWord) num = enNumMap[enWord.toLowerCase()];

    if (num) {
      matches.push({ index: match.index, num: Number(num), length: match[0].length });
    }
  }

  // 根据位置切分描述文本
  for (let i = 0; i < matches.length; i++) {
    const current = matches[i];
    const next = matches[i + 1];
    const startIdx = current.index + current.length;
    const endIdx = next ? next.index : text.length;

    let descText = text.substring(startIdx, endIdx)
      .replace(/^[：:\s—\-–]+/, '')
      .replace(/\n+$/, '')
      .trim();

    if (descText && current.num) {
      descriptions[`${current.num}图`] = descText;
    }
  }

  // 兜底：旧格式
  if (Object.keys(descriptions).length === 0) {
    const pattern = /第\s*(\d+)\s*张图片([（(][^）)]+[）)])\s*[：:]\s*([\s\S]*?)(?=第\s*\d+\s*张图片|$)/g;
    while ((match = pattern.exec(text)) !== null) {
      const num = match[1];
      const size = match[2];
      let value = match[3].trim().replace(/\n+$/, '');
      if (value) {
        descriptions[`${num}图`] = `第 ${num} 张图片${size}：${value}`;
      }
    }
  }
}

// 5. 从 Edit Fields 节点提取 cpimage 开头的 binary
let editFieldsImageCount = 0;
let editFieldsConnected = false;

try {
  let editFieldsNode;
  try { editFieldsNode = $('Edit Fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('Edit_Fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('edit-fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('Edit Fields2'); } catch(e) {}

  const editFieldsOutput = editFieldsNode ? editFieldsNode.all() : [];

  for (const item of editFieldsOutput) {
    if (!item?.binary) continue;
    for (const key in item.binary) {
      if (key.startsWith('cpimage')) {
        const newKey = `${++index}图`;
        images[newKey] = {
          ...item.binary[key],
          sourceNode: 'Edit Fields',
          sourceField: key
        };
        editFieldsImageCount++;
      }
    }
  }
  editFieldsConnected = editFieldsImageCount > 0;
} catch (err) {
  console.error("Edit Fields node error:", err.message);
}

// ================================================
// 6. 【新增】从 Edit Image 节点提取 所有 图片 binary
// ================================================
let editImageImageCount = 0;
let editImageConnected = false;

try {
  let editImageNode;
  try { editImageNode = $('Edit Image'); } catch(e) {}
  try { if (!editImageNode) editImageNode = $('Edit_Image'); } catch(e) {}
  try { if (!editImageNode) editImageNode = $('edit-image'); } catch(e) {}

  const editImageOutput = editImageNode ? editImageNode.all() : [];

  for (const item of editImageOutput) {
    if (!item?.binary) continue;
    for (const key in item.binary) {
      // 提取 Edit Image 输出的 所有图片（不限制名称）
      const newKey = `${++index}图`;
      images[newKey] = {
        ...item.binary[key],
        sourceNode: 'Edit Image',
        sourceField: key
      };
      editImageImageCount++;
    }
  }
